const jsonData = items[0].json;
const customFields = jsonData.custom_fields;
const result = {
  task_id: jsonData.id,
  name: jsonData.name,
  status: jsonData.status.status
};

customFields.forEach(field => {
  const fieldId = field.id;
  let fieldValue;
  let fieldObject = {
    id: fieldId,
    name: field.name
  };

  // Tratamento do valor do campo
  if (field.type === 'users' && Array.isArray(field.value)) {
    const allIds = field.value.map(user => user.id).join(',');
    const userDetails = {};
    field.value.forEach(user => {
      userDetails[user.id] = {
        id: user.id,
        name: user.username,
        email: user.email
      };
    });
    fieldValue = {
      geral: allIds,
      ...userDetails
    };
  } else if (field.type === 'drop_down' && field.value !== undefined && field.value !== null) {
    const selectedOption = field.type_config.options.find(opt => opt.orderindex === field.value);
    if (selectedOption) {
      fieldValue = {
        id: selectedOption.id,
        name: selectedOption.name,
        value: selectedOption.orderindex
      };
    } else {
      fieldValue = '';
    }
  } else if (field.type === 'labels' && Array.isArray(field.value)) {
    fieldValue = field.value.map(optionId => {
      const option = field.type_config.options.find(opt => opt.id === optionId);
      if (option) {
        return {
          id: option.id,
          name: option.label,
          color: option.color
        };
      }
      return null;
    }).filter(Boolean);
  } else if (field.type === 'tasks' && Array.isArray(field.value)) {
    fieldValue = field.value.map(task => ({
      id: task.id,
      name: task.name,
      status: task.status
    }));
  } else if (field.type === 'emoji') {
    fieldValue = field.value || '';
  } else {
    fieldValue = field.value !== undefined && field.value !== null ? field.value : '';
  }

  fieldObject.value = fieldValue;

  // Apenas adiciona options se o campo tiver opções configuradas
  if (field.type_config && field.type_config.options) {
    const options = {};
    field.type_config.options.forEach(opt => {
      options[opt.id] = {
        id: opt.id,
        name: opt.label || opt.name
      };
    });
    if (Object.keys(options).length > 0) {
      fieldObject.options = options;
    }
  }

  result[fieldId] = fieldObject;
});

return [{ json: result }];

// Obter o corpo da requisição
const body = $('OrganizarClickUp').first().json;

// Função para verificar se um campo está vazio
function campoVazio(valor) {
    return valor === null || valor === undefined || valor.toString().trim() === '';
}

// Mapeamento de chaves internas do body para nomes reais
const nomesReais = {
  "16920421-85b5-47a6-9f25-ddeaef905257": "Valor do Fechamento"
};

// Verifica quais campos estão vazios e retorna os nomes reais
const camposReprovados = Object.keys(nomesReais)
    .filter(fieldId => campoVazio(body[fieldId]?.value))
    .map(fieldId => nomesReais[fieldId]);

// Se houver campos reprovados
if (camposReprovados.length > 0) {
    const mensagemFormatada = `❌ Reprovado!\n\n📋 Necessário preencher os seguintes campos:\n\n🔸 ${camposReprovados.join('\n🔸 ')}`;

    return [
        {
            json: {
                dados: 'Reprovado',
                camposReprovados,
                mensagem: mensagemFormatada
            }
        }
    ];
}

// Caso contrário, retorna o corpo original
return [
    {
        json: body
    }
];

